window.PACTO.acts["reg-2018-1806"]={"label": "REGOLAMENTO (UE) 2018/1806 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2018/1806", "file": "ext-reg-2018-1806.html", "external": true, "version": "consolidato 2025-12-30", "eurlex": "https://eur-lex.europa.eu/eli/reg/2018/1806/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Il presente regolamento stabilisce quali sono i paesi terzi i cui cittadini sono soggetti all'obbligo del visto e quali quelli i cui cittadini ne sono esenti, procedendo a una valutazione, caso per caso, di vari criteri che attengono, in particolare, all'immigrazione clandestina, all'ordine pubblico e alla sicurezza, ai vantaggi economici, segnatamente in termini di turismo e commercio estero, e alle relazioni esterne dell'Unione con i paesi terzi in questione, includendo anche considerazioni relative ai diritti umani e alle libertà fondamentali nonché tenendo conto delle implicazioni di coerenza regionale e reciprocità.</p>"]]}, "2": {"label": "Articolo 2", "heading": "", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento, per «visto» s'intende un visto quale definito all'articolo 2, paragrafo 2, lettera a), del regolamento (CE) n. 810/2009 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n).</p>"]]}, "3": {"label": "Articolo 3", "heading": "", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I cittadini dei paesi terzi che figurano nell'elenco di cui all'allegato I devono essere in possesso di visto all'atto dell'attraversamento delle frontiere esterne degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatti salvi gli obblighi che discendono dall'accordo europeo relativo alla soppressione dei visti per i rifugiati, del Consiglio d'Europa, firmato a Strasburgo il 20 aprile 1959, i rifugiati statutari e gli apolidi devono essere muniti di un visto per attraversare le frontiere esterne degli Stati membri, se il paese terzo in cui risiedono e che ha rilasciato il loro documento di viaggio è un paese terzo che figura nell'elenco dell'allegato I del presente regolamento.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I cittadini dei paesi terzi che figurano nell'elenco dell'allegato II sono esentati dall'obbligo di cui all'articolo 3, paragrafo 1, per soggiorni la cui durata globale non sia superiore a 90 giorni su un periodo di 180 giorni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Inoltre, sono esentate dall'obbligo di visto le persone seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini dei paesi terzi di cui all'elenco dell'allegato I del presente regolamento, titolari di lasciapassare per il traffico frontaliero locale rilasciati dagli Stati membri in applicazione del regolamento (CE) n. 1931/2006, allorché tali titolari esercitano il loro diritto nell'ambito di un regime di traffico frontaliero locale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli allievi di istituti scolastici di un paese terzo che figura nell'elenco dell'allegato I del presente regolamento, che risiedono in uno Stato membro che applica la decisione 94/795/GAI del Consiglio (\n<span class=\"superscript\">2</span>\n), e che partecipano a un viaggio scolastico di gruppo accompagnati da un insegnante dell'istituto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i rifugiati statutari, gli apolidi e altre persone che non possiedono la nazionalità di nessun paese, che risiedono in uno Stato membro e che sono titolari di un documento di viaggio rilasciato da tale Stato membro.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "", "anchor": "art_5", "frags": [[null, "<p class=\"norm\">Ai cittadini di nuovi paesi terzi già cittadini di paesi terzi che figuravano negli elenchi degli allegati I e II si applicano rispettivamente gli articoli 3 e 4 finché il Consiglio non decida altrimenti secondo la procedura prevista dalla pertinente disposizione del TFUE.</p>"]]}, "6": {"label": "Articolo 6", "heading": "", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri possono prevedere deroghe all'obbligo del visto di cui all'articolo 3 o all'esenzione da tale obbligo di cui all'articolo 4, per le seguenti categorie di persone:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i titolari di passaporti diplomatici, di passaporti di servizio/ufficiali o di passaporti speciali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i membri degli equipaggi civili di aerei e navi nell'esercizio delle loro funzioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i membri degli equipaggi civili di navi che si recano a terra e che sono in possesso di un documento di identità per marittimi rilasciato ai sensi delle convenzioni dell'Organizzazione internazionale del lavoro n. 108 del 13 maggio 1958 oppure n. 185 del 19 giugno 2003 o della convenzione sulla facilitazione del traffico marittimo internazionale del 9 aprile 1965 dell'Organizzazione marittima internazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli equipaggi e i membri delle missioni di soccorso o salvataggio in caso di catastrofe o incidente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli equipaggi civili di navi che operano in acque interne internazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i titolari di documenti di viaggio rilasciati da organizzazioni internazionali intergovernative di cui sia membro almeno uno Stato membro o da altre entità riconosciute dallo Stato membro interessato quale soggetti di diritto internazionale ai funzionari di tali organizzazioni o entità.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Uno Stato membro può dispensare dall'obbligo del visto di cui all'articolo 3:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli allievi di istituti scolastici di un paese terzo che figura nell'elenco dell'allegato I, che risiedono in un paese terzo che figura nell'elenco dell'allegato II o in Svizzera e in Liechtenstein, quando tali allievi partecipano a un viaggio scolastico di gruppo accompagnati da un insegnante dell'istituto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i rifugiati statutari e gli apolidi, se il paese terzo in cui risiedono e che ha rilasciato il loro documento di viaggio è uno dei paesi terzi dell'allegato II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i membri delle forze armate che si spostano nell'ambito della NATO e del Partenariato per la pace e titolari dei documenti d'identità e di missione previsti dalla convenzione tra gli Stati partecipanti all'organizzazione del trattato del Nord Atlantico sullo statuto delle loro forze armate del 19 giugno 1951;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatti salvi gli obblighi derivanti dall'accordo europeo relativo alla soppressione dei visti dei rifugiati, del Consiglio d'Europa, firmato a Strasburgo il 20 aprile 1959, i rifugiati statutari, gli apolidi e altre persone che non possiedono la cittadinanza di nessun paese, che risiedono in Irlanda e sono titolari di un documento di viaggio rilasciato dall'Irlanda che è riconosciuto dallo Stato membro interessato.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono prevedere deroghe all'esenzione dall'obbligo del visto di cui all'articolo 4, per le persone che esercitano un'attività remunerata durante il loro soggiorno.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "", "anchor": "art_7", "frags": [[null, "<p class=\"norm\">L'applicazione, da parte di un paese terzo di cui all'allegato II, dell'obbligo del visto per i cittadini di almeno uno Stato membro comporta l'applicazione delle seguenti disposizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">entro trenta giorni dall'applicazione dell'obbligo del visto da parte del paese terzo lo Stato membro interessato ne dà notifica per iscritto al Parlamento europeo, al Consiglio e alla Commissione.</p>\n<p class=\"list\">Tale notifica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">precisa la data di applicazione dell'obbligo del visto e i tipi di documenti di viaggio e di visti in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contiene una circostanziata illustrazione delle misure preliminari adottate dallo Stato membro interessato al fine di garantire l'esenzione dall'obbligo del visto con il paese terzo in questione, nonché tutte le informazioni pertinenti.</p>\n</div>\n</div>\n<p class=\"list\">Le informazioni in merito a tale notifica sono pubblicate senza indugio dalla Commissione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> e comprendono la data di applicazione dell'obbligo del visto e i tipi di documenti di viaggio e di visti in questione.</p>\n<p class=\"list\">Se il paese terzo decide di revocare l'obbligo del visto prima della scadenza del termine di cui al primo comma del presente punto, la notifica non è effettuata oppure è ritirata e le informazioni non sono pubblicate;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione, immediatamente dopo la data della pubblicazione di cui al terzo comma, lettera a), e di concerto con lo Stato membro interessato, interviene presso le autorità del paese terzo in questione, in particolare nel settore politico, economico e commerciale, ai fini della reintroduzione o dell'introduzione dell'esenzione dall'obbligo del visto e ne informa senza indugio il Parlamento europeo e il Consiglio;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se entro novanta giorni dalla data della pubblicazione di cui al terzo comma, lettera a), e malgrado tutti gli interventi effettuati ai sensi della lettera b) il paese terzo non ha revocato l'obbligo del visto, lo Stato membro interessato può chiedere alla Commissione di sospendere l'esenzione dall'obbligo del visto per determinate categorie di cittadini di tale paese terzo. Se uno Stato membro avanza una tale richiesta, ne informa il Parlamento europeo e il Consiglio;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione, nel valutare ulteriori interventi a norma delle lettere e), f) o h), tiene conto dell'esito delle misure adottate dallo Stato membro interessato al fine di garantire l'esenzione dall'obbligo del visto, degli interventi effettuati a norma della lettera b) e delle conseguenze della sospensione dell'esenzione dall'obbligo del visto per le relazioni esterne dell'Unione e dei suoi Stati membri con il paese terzo in questione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il paese terzo interessato non ha revocato l'obbligo del visto, la Commissione, entro sei mesi dalla data della pubblicazione di cui al terzo comma, lettera a), e successivamente ad intervalli non superiori a sei mesi in un arco di tempo complessivo che non può superare la data di decorrenza dell'atto delegato di cui alla lettera f) o la data alla quale sono sollevate obiezioni a tale atto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adotta, su richiesta dello Stato membro interessato o di propria iniziativa, un atto di esecuzione che sospende temporaneamente l'esenzione dall'obbligo del visto per determinate categorie di cittadini del paese terzo interessato per un periodo massimo di sei mesi. Tale atto di esecuzione fissa, entro novanta giorni dalla sua entrata in vigore, una data dalla quale decorrono gli effetti della sospensione dell'esenzione dall'obbligo del visto, tenendo conto delle risorse disponibili nei consolati degli Stati membri. Quando adotta atti di esecuzione successivi, la Commissione può prorogare il periodo di tale sospensione di ulteriori periodi massimi di sei mesi e può modificare le categorie di cittadini del paese terzo in questione per le quali è sospesa l'esenzione dall'obbligo del visto.</p>\n<p class=\"list\">Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 11, paragrafo 2. Fatta salva l'applicazione dell'articolo 6, durante i periodi di sospensione tutte le categorie di cittadini del paese terzo di cui all'atto di esecuzione devono essere in possesso del visto all'atto dell'attraversamento delle frontiere esterne degli Stati membri; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta al comitato di cui all'articolo 11, paragrafo 1, una relazione che valuta la situazione e precisa i motivi per cui ha deciso di non sospendere l'esenzione dall'obbligo del visto e ne informa il Parlamento europeo e il Consiglio.</p>\n<p class=\"list\">Tale relazione tiene conto di tutti gli elementi pertinenti, quali quelli di cui alla lettera d). Il Parlamento europeo e il Consiglio possono procedere a un dibattito politico sulla base di tale relazione;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se entro 24 mesi dalla data della pubblicazione di cui al terzo comma, lettera a), il paese terzo interessato non ha revocato l'obbligo del visto, la Commissione adotta, a norma dell'articolo 10, un atto delegato che sospende temporaneamente l'esenzione dall'obbligo del visto per un periodo di dodici mesi per i cittadini di tale paese terzo. L'atto delegato fissa, entro 90 giorni dalla sua entrata in vigore, una data dalla quale decorrono gli effetti della sospensione dell'esenzione dall'obbligo del visto, tenendo conto delle risorse disponibili nei consolati degli Stati membri, e modifica di conseguenza l'allegato II. Tale modifica consiste nell'inserire, in corrispondenza del nome del paese terzo in questione, una nota in calce in cui sia indicato che l'esenzione dall'obbligo del visto è sospesa nei confronti di tale paese terzo e sia precisato il periodo di detta sospensione.</p>\n<p class=\"list\">Dalla data di decorrenza della sospensione dell'esenzione dall'obbligo del visto per i cittadini del paese terzo interessato o qualora sia stata sollevata un'obiezione all'atto delegato a norma dell'articolo 10, paragrafo 7, cessa di produrre effetti qualsiasi atto di esecuzione adottato a norma della lettera e) del presente articolo concernente tale paese terzo. Qualora la Commissione presenti una proposta legislativa conformemente alla lettera h), il periodo di sospensione dell'esenzione dall'obbligo del visto di cui al primo comma della presente lettera è prorogato di sei mesi. La nota in calce di cui a tale comma è modificata di conseguenza.</p>\n<p class=\"list\">Fatta salva l'applicazione dell'articolo 6, durante i periodi di tale sospensione i cittadini del paese terzo interessato dall'atto delegato devono essere in possesso del visto all'atto dell'attraversamento delle frontiere esterne degli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi notifica successiva effettuata da un altro Stato membro a norma della lettera a) concernente il medesimo paese terzo durante il periodo di applicazione delle misure adottate a norma delle lettere e) o f) in relazione a detto paese terzo è inglobata nelle procedure in corso senza prorogare i termini o i periodi stabiliti in tali lettere;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se entro sei mesi dall'entrata in vigore dell'atto delegato di cui alla lettera f) il paese terzo in questione non ha revocato l'obbligo del visto, la Commissione può presentare una proposta legislativa di modifica del presente regolamento diretta a spostare il riferimento al paese terzo dall'allegato II all'allegato I;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le procedure di cui alle lettere e), f) e h) non pregiudicano il diritto della Commissione di presentare in qualsiasi momento una proposta legislativa di modifica del presente regolamento diretta a spostare il riferimento al paese terzo interessato dall'allegato II all'allegato I;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora il paese terzo in questione revochi l'obbligo del visto, lo Stato membro interessato ne dà immediata notifica al Parlamento europeo, al Consiglio e alla Commissione. La notifica è pubblicata senza indugio dalla Commissione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Qualsiasi atto di esecuzione o atto delegato adottato a norma della lettera e) o f) concernente il paese terzo in questione cessa di produrre effetti sette giorni dopo la pubblicazione di cui al primo comma della presente lettera. Nel caso in cui il paese terzo in questione abbia introdotto un obbligo di visto per i cittadini di due o più Stati membri, l'atto di esecuzione o l'atto delegato concernente detto paese terzo cessa di produrre effetti sette giorni dopo la pubblicazione della notifica relativa all'ultimo Stato membro i cui cittadini erano sottoposti all'obbligo del visto da parte di tale paese terzo. La nota in calce di cui al primo comma, lettera f), è soppressa nel momento in cui l'atto delegato interessato cessa di produrre effetti. Le informazioni su tale cessazione degli effetti sono pubblicate senza indugio dalla Commissione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>"], [null, "<p class=\"norm\">Nel caso in cui il paese terzo in questione revochi l'obbligo del visto senza che lo Stato membro interessato ne dia notifica a norma del primo comma della presente lettera, la Commissione procede senza indugio, di propria iniziativa, alla pubblicazione di cui allo stesso comma e si applica il secondo comma della presente lettera.</p>"]]}, "8": {"label": "Articolo 8", "heading": "", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 4, l’esenzione dall’obbligo del visto per i cittadini di un paese terzo che figura nell’elenco di cui all’allegato II può essere sospesa temporaneamente, in base a dati pertinenti e oggettivi, conformemente alle condizioni e alle procedure di cui agli articoli da 8 <span class=\"italics\">bis</span> a 8 <span class=\"italics\">septies</span> («meccanismo di sospensione»).</div>\n</div>"], [null, "<p class=\"norm\">Il meccanismo di sospensione può essere attivato da una notifica di uno Stato membro alla Commissione in conformità dell’articolo 8 <span class=\"italics\">ter</span> o sulla base dell’analisi condotta dalla Commissione stessa in conformità dell’articolo 8 <span class=\"italics\">quater</span>.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora sia stato concluso un accordo di esenzione dal visto per soggiorni di breve durata tra l’Unione e un paese terzo che figura nell’elenco di cui all’allegato II, si applicano, fatte salve le pertinenti disposizioni relative ai motivi di sospensione e alle procedure stabilite in tale accordo, gli articoli 8 <span class=\"italics\">bis</span>, 8 <span class=\"italics\">sexies</span> e 8 <span class=\"italics\">septies</span> del presente regolamento.</div>\n</div>"]]}, "8a": {"label": "Articolo 8 bis", "heading": "", "anchor": "art_8a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il meccanismo di sospensione può essere attivato sulla base di uno dei motivi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un aumento sostanziale del numero di cittadini di un paese terzo che figura nell’elenco di cui all’allegato II ai quali è stato rifiutato l’ingresso nel territorio di uno Stato membro o che soggiornano sul territorio di uno Stato membro senza averne il diritto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un aumento sostanziale del numero di domande d’asilo presentate da cittadini di un paese terzo che figura nell’elenco di cui all’allegato II il cui tasso di riconoscimento è basso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una diminuzione nella cooperazione in materia di riammissione con un paese terzo che figura nell’elenco di cui all’allegato II o altri casi di mancata cooperazione in materia di riammissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un rischio significativo o una minaccia imminente all’ordine pubblico o alla sicurezza interna degli Stati membri collegati a un paese terzo che figura nell’elenco di cui all’allegato II, in particolare qualora derivi da uno dei fattori seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un aumento significativo dei reati gravi collegati ai cittadini di tale paese terzo, suffragato da informazioni e dati pertinenti, oggettivi e concreti forniti dalle autorità competenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">minacce ibride;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">carenze sistemiche nel diritto o nelle procedure relativi alla sicurezza dei documenti;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione, da parte di un paese terzo che figura nell’elenco di cui all’allegato II, di un programma di cittadinanza per investitori nell’ambito del quale la cittadinanza è concessa a una persona, in cambio di pagamenti o investimenti predeterminati, senza che tale persona abbia alcun legame effettivo con tale paese terzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il mancato allineamento della politica in materia di visti di un paese terzo che figura nell’elenco di cui all’allegato II alla politica in materia di visti dell’Unione, il quale, in particolare a causa della prossimità geografica del paese terzo all’Unione, potrebbe portare a un aumento sostanziale del numero di cittadini di altri paesi terzi, che dopo aver soggiornato o transitato nel territorio di quest’ultimo entrano irregolarmente nel territorio degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in relazione ai paesi terzi che figurano nell’elenco di cui all’allegato II, a seguito della conclusione positiva di un dialogo sulla liberalizzazione dei visti con l’Unione, il mancato rispetto da parte del paese terzo dei requisiti specifici basati sull’articolo 1 e utilizzati per valutare l’appropriatezza della concessione dell’esenzione dall’obbligo del visto ai propri cittadini;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un deterioramento delle relazioni esterne dell’Unione con un paese terzo che figura nell’elenco di cui all’allegato II a causa di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gravi violazioni, da parte di tale paese terzo, dei principi enunciati nella Carta delle Nazioni Unite;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gravi violazioni, da parte di tale paese terzo, delle libertà fondamentali o degli obblighi derivanti dal diritto internazionale dei diritti umani o dal diritto internazionale umanitario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gravi violazioni, da parte di tale paese terzo, del diritto internazionale e delle norme giuridiche internazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">inosservanza, da parte di tale paese terzo, di decisioni e sentenze dei tribunali internazionali; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">atti ostili compiuti da tale paese terzo nei confronti dell’Unione o degli Stati membri al fine di destabilizzare o compromettere la società o le istituzioni che sono fondamentali per l’ordine pubblico e la sicurezza interna dell’Unione o degli Stati membri;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi altro motivo di sospensione previsto da un accordo di esenzione dal visto per soggiorni di breve durata tra l’Unione e un paese terzo che figura nell’elenco di cui all’allegato II, limitatamente all’ambito di applicazione dell’accordo in questione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1, lettere a) e b), del paragrafo 1, lettera d), punto i), e del paragrafo 4, per aumento sostanziale si intende il superamento di una soglia del 30 %, a meno che la Commissione, sulla base dell’esame a norma dell’articolo 8 <span class=\"italics\">ter</span>, paragrafo 5, o dell’analisi di cui all’articolo 8 <span class=\"italics\">quater</span>, paragrafo 2, concluda che nel caso specifico è applicabile una soglia diversa. La Commissione motiva debitamente qualsiasi conclusione di questo tipo.</div>\n</div>"], [null, "<p class=\"norm\">Entro il 31 dicembre 2028, la Commissione valuta in che modo è stata attuata la soglia di cui al primo comma e presenta i risultati di tale valutazione al Parlamento europeo e al Consiglio. La valutazione si concentra, in particolare, sulla pertinenza della soglia ai fini del meccanismo di sospensione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1, lettera b), del presente articolo, per tasso di riconoscimento basso si intende un tasso di riconoscimento delle domande di asilo inferiore al 20 %, a meno che la Commissione, sulla base del proprio esame a norma dell’articolo 8 <span class=\"italics\">ter</span>, paragrafo 5, o della propria analisi di cui all’articolo 8 <span class=\"italics\">quater</span>, paragrafo 2, concluda che nel caso specifico è applicabile un tasso di riconoscimento diverso. La Commissione motiva debitamente qualsiasi conclusione di questo tipo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1, lettera c), per diminuzione nella cooperazione in materia di riammissione con un paese terzo che figura nell’elenco di cui all’allegato II si intende un aumento sostanziale, suffragato da dati adeguati, del tasso di rifiuto delle domande di riammissione presentate da uno Stato membro a tale paese terzo per cittadini di quest’ultimo o, qualora un accordo di riammissione concluso tra l’Unione o lo Stato membro e il paese terzo in questione lo preveda, per cittadini di paesi terzi che sono transitati in quel paese terzo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini del paragrafo 1, lettera c), possono essere considerati altri casi di mancata cooperazione in materia di riammissione i seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il rifiuto o il mancato tempestivo esame delle domande di riammissione, compresa la mancata assistenza nell’identificazione dei cittadini di paesi terzi per i quali uno Stato membro ha presentato domanda di riammissione o la creazione in altro modo di ostacoli pratici persistenti all’esecuzione dei rimpatri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il mancato tempestivo rilascio di documenti di viaggio ai fini del rimpatrio di cittadini di paesi terzi entro i termini specificati in un accordo di riammissione con un paese terzo che figura nell’elenco di cui all’allegato II o la mancata accettazione dei documenti di viaggio europei rilasciati dopo la scadenza dei termini specificati in tale accordo di riammissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la denuncia o la sospensione dell’accordo di riammissione concluso tra un l’Unione e un paese terzo che figura nell’elenco di cui all’allegato II.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "8b": {"label": "Articolo 8 ter", "heading": "", "anchor": "art_8b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può informare la Commissione qualora, su un periodo compreso tra due e dodici mesi rispetto al medesimo periodo dell’anno precedente o agli ultimi due mesi precedenti la data di applicazione dell’esenzione dall’obbligo del visto per i cittadini di un paese terzo che figura nell’elenco di cui all’allegato II, sussistano in relazione a tale Stato membro una o più circostanze che costituiscono motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettere a), b) e c), e di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettera d), punto i).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può notificare alla Commissione la sussistenza di una o più circostanze che costituiscono motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettera d), punti ii) e iii), e di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettere e), f) e i).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le notifiche di cui ai paragrafi 1 e 2 del presente articolo precisano i motivi su cui si basano. Se del caso, tali notifiche contengono dati e statistiche pertinenti, nonché una circostanziata descrizione delle misure preliminari adottate dallo Stato membro interessato per porre rimedio alle circostanze all’origine della notifica. Uno Stato membro può precisare nella propria notifica le categorie di cittadini del paese terzo in questione che devono essere contemplate da un atto di esecuzione adottato a norma dell’articolo 8 <span class=\"italics\">sexies</span>, paragrafo 1, fornendo motivazioni dettagliate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione informa immediatamente il Parlamento europeo e il Consiglio di ogni notifica ricevuta a norma del paragrafo 1 o 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione esamina senza indugi ogni notifica presentata a norma del paragrafo 1 o 2 del presente articolo, tenendo conto di quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se sussistono circostanze che costituiscono motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettere a), b), c), d), e), f) o i);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di Stati membri interessati da tali circostanze;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le ripercussioni generali di tali circostanze sulla situazione migratoria nell’Unione quale emerge dai dati forniti dagli Stati membri o in possesso della Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le relazioni elaborate dalla guardia di frontiera e costiera europea, istituita dal regolamento (UE) 2019/1896 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n), dall’Agenzia dell’Unione europea per l’asilo, istituita dal regolamento (UE) 2021/2303 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">4</span>\n), o dall’Agenzia dell’Unione europea per la cooperazione nell’attività di contrasto (Europol), istituita dal regolamento (UE) 2016/794 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">5</span>\n), o da qualsiasi altra istituzione, organo o organismo dell’Unione o organizzazione internazionale competente, ove le circostanze dello specifico caso lo richiedano;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni indicazione fornita da uno Stato membro nella propria notifica in relazione a possibili misure a norma dell’articolo 8 <span class=\"italics\">sexies</span>, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la questione generale dell’ordine pubblico e della sicurezza interna, di concerto con lo Stato membro interessato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Nell’ambito dell’esame a norma del paragrafo 5, la Commissione valuta la necessità, la proporzionalità e le conseguenze di una sospensione dell’esenzione dall’obbligo del visto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione informa il Parlamento europeo e il Consiglio dei risultati del proprio esame a norma del paragrafo 5.</div>\n</div>"]]}, "8c": {"label": "Articolo 8 quater", "heading": "", "anchor": "art_8c", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione monitora periodicamente la sussistenza delle circostanze che costituiscono i motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1.</div>\n</div>"], [null, "<p class=\"norm\">In particolare, la Commissione monitora inoltre se i paesi terzi che figurano nell’elenco di cui all’allegato II, a seguito della conclusione positiva di un dialogo sulla liberalizzazione dei visti con l’Unione, continuino a rispettare i requisiti specifici basati sull’articolo 1 e utilizzati per valutare l’appropriatezza di concedere ai loro cittadini l’esenzione dall’obbligo del visto.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Dopo aver analizzato dati, relazioni e statistiche pertinenti, inclusi dati, relazioni e statistiche provenienti da qualsiasi istituzione, organo od organismo dell’Unione, la Commissione informa il Parlamento europeo e il Consiglio qualora disponga di informazioni concrete e affidabili in merito alla sussistenza di una delle circostanze che costituiscono motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1. La Commissione adotta quindi le misure necessarie in conformità degli articoli 8 <span class=\"italics\">sexies</span> e 8 <span class=\"italics\">septies</span>.</div>\n</div>"]]}, "8d": {"label": "Articolo 8 quinquies", "heading": "", "anchor": "art_8d", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione riferisce al Parlamento europeo e al Consiglio in merito al monitoraggio svolto a norma dell’articolo 8 <span class=\"italics\">quater</span>, paragrafo 1, in relazione ai paesi terzi che figurano nell’elenco di cui all’allegato II a seguito della conclusione positiva di un dialogo sulla liberalizzazione dei visti con l’Unione. Tale attività di comunicazione è svolta almeno una volta l’anno e per un periodo di sette anni dalla data di entrata in vigore dell’atto giuridico che esenta i cittadini del paese terzo in questione dall’obbligo del visto. Dopo tale periodo, la Commissione riferisce al Parlamento europeo e al Consiglio in merito al monitoraggio ogniqualvolta lo ritenga necessario ovvero su richiesta del Parlamento europeo o del Consiglio. Tali relazioni si concentrano sui paesi terzi per i quali la Commissione ritiene, sulla base di informazioni concrete e affidabili, che non siano più soddisfatti alcuni requisiti specifici basati sull’articolo 1 e utilizzati per valutare l’appropriatezza della concessione dell’esenzione dall’obbligo del visto ai loro cittadini.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Oltre agli obblighi di comunicazione previsti dal paragrafo 1 del presente articolo, ogniqualvolta lo ritenga necessario ovvero su richiesta del Parlamento europeo o del Consiglio, la Commissione riferisce al Parlamento europeo e al Consiglio in merito al monitoraggio svolto a norma dell’articolo 8 <span class=\"italics\">quater</span>, paragrafo 1, in relazione ad altri paesi terzi che figurano nell’elenco di cui all’allegato II.</div>\n</div>"]]}, "8e": {"label": "Articolo 8 sexies", "heading": "", "anchor": "art_8e", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione adotta un atto di esecuzione che sospende per un periodo di 12 mesi l’esenzione dall’obbligo del visto per i cittadini di un paese terzo qualora:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">abbia deciso, sulla base del proprio esame a norma dell’articolo 8 <span class=\"italics\">ter</span>, paragrafo 5, o della propria analisi di cui all’articolo 8 <span class=\"italics\">quater</span>, paragrafo 2, che tali misure sono necessarie; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una maggioranza semplice di Stati membri abbia notificato alla Commissione che sussistono le circostanze che costituiscono motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettere a), b), c), d), e), f) o i).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’adottare una decisione di cui alla lettera a), paragrafo 1, la Commissione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">collabora a stretto contatto con il paese terzo interessato per trovare soluzioni alternative di lungo periodo con riguardo alla circostanza o alle circostanze pertinenti che costituiscono motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tiene conto del contesto politico, delle questioni economiche in gioco e delle conseguenze di una sospensione dell’esenzione dall’obbligo del visto per le relazioni esterne complessive dell’Unione e degli Stati membri con il paese terzo interessato; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tiene altresì conto delle conseguenze di una sospensione dell’esenzione dall’obbligo del visto per la società civile del paese terzo interessato, in particolare qualora la situazione dei diritti umani in tale paese terzo si sia deteriorata.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La sospensione prevista da un atto di esecuzione adottato a norma del paragrafo 1 del presente articolo si applica a determinate categorie di cittadini del paese terzo interessato, facendo riferimento ai pertinenti tipi di documenti di viaggio e, se del caso, a criteri aggiuntivi. Nel determinare a quali categorie si applica la sospensione, la Commissione include, in base alle informazioni disponibili, categorie sufficientemente ampie per contribuire in maniera efficace a porre rimedio alle circostanze che hanno portato alla sospensione, nel rispetto del principio di proporzionalità e di non discriminazione in linea con l’articolo 21 della Carta dei diritti fondamentali dell’Unione europea. Gli atti di esecuzione adottati a norma del paragrafo 1 del presente articolo stabiliscono la data dalla quale decorrono gli effetti della sospensione dell’esenzione dall’obbligo del visto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione presenta un progetto di atto di esecuzione di cui al paragrafo 1 del presente articolo al comitato di cui all’articolo 11, paragrafo 1:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">entro un mese da quando:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ha ricevuto una notifica da parte di uno Stato membro a norma dell’articolo 8 <span class=\"italics\">ter</span>, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ha informato il Parlamento europeo e il Consiglio della propria analisi di cui all’articolo 8 <span class=\"italics\">quater</span>, paragrafo 2; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ha ricevuto una notifica da parte di una maggioranza semplice di Stati membri riguardo alla sussistenza di circostanze che costituiscono motivi di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettera a), b), c), d), e), f) o i);</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">entro due mesi da quando ha ricevuto una notifica da parte di uno Stato membro a norma dell’articolo 8 <span class=\"italics\">ter</span>, paragrafo 2.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli atti di esecuzione di cui al paragrafo 1 del presente articolo sono adottati secondo la procedura di esame di cui all’articolo 11, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In deroga ai paragrafi da 1 a 4 del presente articolo, all’articolo 8 <span class=\"italics\">ter</span> e all’articolo 8 <span class=\"italics\">quater</span>, paragrafo 2, ove giustificato dall’urgenza della situazione, qualora disponga di informazioni concrete e affidabili in merito alla sussistenza di una delle circostanze che costituiscono motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, e decida che è necessaria un’azione rapida, la Commissione adotta un atto di esecuzione che sospende temporaneamente l’esenzione dall’obbligo del visto per tutte le categorie di cittadini del paese terzo interessato, o per alcune di esse, per un periodo di 12 mesi. Tali atti di esecuzione stabiliscono la data dalla quale decorrono gli effetti della sospensione dell’esenzione dall’obbligo del visto.</div>\n</div>"], [null, "<p class=\"norm\">Gli atti di esecuzione di cui al primo comma del presente paragrafo sono adottati secondo la procedura d’esame di cui all’articolo11, paragrafo 2. Il presidente del comitato previsto dall’articolo 11, paragrafo 1, valuta la possibilità di abbreviare il termine per la convocazione di una riunione del comitato di cui all’articolo 3, paragrafo 3, secondo comma, del regolamento (UE) n. 182/2011, e di ricorrere alla procedura scritta di cui all’articolo 3, paragrafo 5, di tale regolamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 6, durante il periodo di sospensione le categorie di cittadini del paese terzo contemplate da un atto di esecuzione adottato a norma del paragrafo 1 o 5 del presente articolo devono essere in possesso di un visto all’atto dell’attraversamento delle frontiere esterne degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Se la Commissione ha adottato un atto di esecuzione a norma del paragrafo 1 o 5 del presente articolo per il motivo di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettera g), per quanto riguarda il mancato rispetto di requisiti specifici in materia di relazioni esterne o diritti fondamentali, o per il motivo di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettera h), sospendendo temporaneamente l’esenzione dall’obbligo del visto per i cittadini di un paese terzo titolari di passaporti diplomatici, di passaporti di servizio/ufficiali o di passaporti speciali, gli Stati membri non prevedono nuove deroghe all’obbligo del visto a norma dell’articolo 6, paragrafo 1, lettera a). Gli Stati membri che hanno accordi bilaterali con il paese terzo interessato adottano le misure necessarie per non applicare le deroghe adottate a norma dell’articolo 6, paragrafo 1, lettera a).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo7 del presente articolo, uno Stato membro che, a norma dell’articolo 6, adotti misure che prevedono nuove deroghe all’obbligo del visto per una categoria di cittadini del paese terzo interessato da un atto di esecuzione adottato a norma del paragrafo 1 o 5 del presente articolo comunica tali misure conformemente all’articolo 12.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Durante il periodo di sospensione la Commissione stabilisce un dialogo rafforzato con il paese terzo interessato al fine di porre rimedio alle circostanze in questione. La Commissione informa il Parlamento europeo e il Consiglio in merito ai progressi e ai risultati del dialogo nonché in merito all’efficacia della sospensione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Qualora sia stato posto rimedio alle circostanze che hanno portato alla sospensione temporanea dell’esenzione dall’obbligo del visto prima della fine del periodo di applicazione dell’atto di esecuzione adottato a norma del paragrafo 1 o 5 del presente articolo, la Commissione adotta un atto di esecuzione per revocare la sospensione temporanea secondo la procedura d’esame di cui all’articolo 11, paragrafo 2.</div>\n</div>"]]}, "8f": {"label": "Articolo 8 septies", "heading": "", "anchor": "art_8f", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se le circostanze che costituiscono motivi di sospensione pertinenti di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, persistono nei confronti di un paese terzo i cui cittadini sono contemplati da un atto di esecuzione adottato a norma dell’articolo 8 <span class=\"italics\">sexies</span>, paragrafo 1 o 5, la Commissione adotta, al più tardi due mesi prima della scadenza del periodo di sospensione di 12 mesi previsto da un atto di esecuzione, un atto delegato in conformità dell’articolo 10 al fine di modificare l’allegato II per sospendere temporaneamente, per un periodo di 24 mesi, l’applicazione di tale allegato per tutti i cittadini del paese terzo interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1 del presente articolo, se l’atto di esecuzione di cui all’articolo 8 <span class=\"italics\">sexies</span>, paragrafo 1 o 5, che contempla i cittadini del paese terzo interessato, è stato adottato per il motivo di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettera g), per quanto riguarda il mancato rispetto di requisiti specifici in materia di relazioni esterne o diritti fondamentali, o per il motivo di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettera h), la Commissione può, mediante un atto delegato di cui al paragrafo 1 del presente articolo, sospendere temporaneamente, per un periodo di 24 mesi, l’applicazione dell’allegato II per determinate categorie di cittadini di tale paese terzo, designate in conformità dei principi di cui all’articolo 8 <span class=\"italics\">sexies</span>, paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La modifica di cui al paragrafo 1 consiste nell’inserire una nota in calce in corrispondenza del nome del paese terzo interessato, in cui sia indicato che l’esenzione dall’obbligo del visto è sospesa nei confronti di tale paese terzo e sia precisato il periodo della sospensione, e in cui siano indicate, se del caso, le categorie designate di cittadini di tale paese terzo alle quali si applica la sospensione. L’atto delegato ha effetto dalla fine del periodo di applicazione dell’atto delegato pertinente di cui all’articolo 8 <span class=\"italics\">sexies</span>, paragrafo 1 o 5.</div>\n</div>"], [null, "<p class=\"norm\">L’articolo 8 <span class=\"italics\">sexies</span>, paragrafo 7, si applica <span class=\"italics\">mutatis mutandis</span>.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Fatti salvi l’articolo 6 e il paragrafo 3 secondo comma, del presente articolo, durante il periodo di sospensione i cittadini del paese terzo contemplati da un atto delegato adottato a norma del paragrafo 1 del presente articolo devono essere in possesso di un visto all’atto dell’attraversamento delle frontiere esterne degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 8 <span class=\"italics\">sexies</span>, paragrafo 7, uno Stato membro che, a norma dell’articolo 6, adotti misure che prevedono nuove deroghe all’obbligo del visto per una categoria di cittadini del paese terzo interessato da un atto delegato adottato a norma del paragrafo 1 del presente articolo comunica tali misure conformemente all’articolo 12.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Prima della fine del periodo di applicazione di un atto delegato adottato a norma del paragrafo 1, la Commissione presenta una relazione al Parlamento europeo e al Consiglio sull’applicazione temporanea della sospensione dell’esenzione dall’obbligo del visto, sul dialogo tra la Commissione e il paese terzo interessato e sulle misure adottate per porre rimedio alle circostanze che hanno portato alla sospensione temporanea dell’esenzione dal visto.</div>\n</div>"], [null, "<p class=\"norm\">Le relazioni di cui al primo comma possono essere accompagnate da una proposta legislativa di modifica del presente regolamento intesa a spostare dall’allegato II all’allegato I il riferimento al paese terzo interessato. In tal caso, la Commissione adotta un atto delegato in conformità dell’articolo 10 al fine di modificare l’allegato II per prorogare il periodo di sospensione dell’esenzione dall’obbligo del visto stabilito dall’atto delegato adottato a norma del paragrafo 1 del presente articolo fino all’entrata in vigore della modifica intesa a spostare all’allegato I il riferimento al paese terzo interessato. Tale proroga non supera il periodo di 24 mesi. La nota in calce che accompagna il riferimento è modificata di conseguenza.</p>"], [null, "<p class=\"norm\">Se, a causa del carattere persistente delle circostanze che costituiscono motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettera g), per quanto riguarda il mancato rispetto di requisiti specifici in materia di relazioni esterne o diritti fondamentali, o delle circostanze che costituiscono motivi di sospensione di cui all’articolo 8 <span class=\"italics\">bis</span>, paragrafo 1, lettera h), un atto delegato adottato a norma del paragrafo 1 del presente articolo è stato applicato ai sensi del paragrafo 2 del presente articolo ai cittadini di un paese terzo titolari di passaporti diplomatici, di passaporti di servizio/ufficiali o di passaporti speciali, la Commissione può indicare nella relazione relativa a tale atto delegato la necessità di adottare un ulteriore atto delegato al fine di prorogare il periodo di sospensione per un periodo aggiuntivo di 24 mesi. In tal caso, il primo e il secondo comma del presente paragrafo si applicano <span class=\"italics\">mutatis mutandis</span>.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora sia stato posto rimedio alle circostanze che hanno portato alla sospensione temporanea dell’esenzione dall’obbligo del visto prima della fine del periodo di applicazione di un atto delegato adottato a norma del paragrafo 1 o 5 del presente articolo, la Commissione adotta un atto delegato in conformità dell’articolo 10 al fine di modificare l’allegato II per revocare la sospensione temporanea.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 10 gennaio 2018 la Commissione presenta al Parlamento europeo e al Consiglio una relazione di valutazione dell'efficacia del meccanismo di reciprocità di cui all'articolo 7 e, se necessario, presenta una proposta legislativa intesa a modificare il presente regolamento. Il Parlamento europeo e il Consiglio deliberano sulla proposta secondo la procedura legislativa ordinaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 29 marzo 2021 la Commissione presenta al Parlamento europeo e al Consiglio una relazione di valutazione dell'efficacia del meccanismo di sospensione di cui all'articolo 8 e, se necessario, presenta una proposta legislativa intesa a modificare il presente regolamento. Il Parlamento europeo e il Consiglio deliberano sulla proposta secondo la procedura legislativa ordinaria.</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all'articolo 7, lettera f), è conferito alla Commissione per un periodo di cinque anni a decorrere da 9 gennaio 2014. La Commissione elabora una relazione sulla delega di potere al più tardi nove mesi prima della scadenza del periodo di cinque anni. La delega di potere è tacitamente prorogata per periodi di identica durata, a meno che il Parlamento europeo o il Consiglio non si oppongano a tale proroga al più tardi tre mesi prima della scadenza di ciascun periodo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M7\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all’articolo 8 <span class=\"italics\">septies</span> è conferito alla Commissione per un periodo di cinque anni a decorrere dal 28 marzo 2017. La Commissione elabora una relazione sulla delega di potere al più tardi nove mesi prima della scadenza del periodo di cinque anni. La delega di potere è tacitamente prorogata per periodi di identica durata, a meno che il Parlamento europeo o il Consiglio non si opponga a tale proroga al più tardi tre mesi prima della scadenza di ciascun periodo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all’articolo 7, lettera f), e all’articolo 8 <span class=\"italics\">septies</span> può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Prima dell'adozione dell'atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell'accordo interistituzionale «Legiferare meglio» del 13 aprile 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L'atto delegato adottato ai sensi dell'articolo 7, lettera f), entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di quattro mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M7\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L’atto delegato adottato ai sensi dell’articolo 8 <span class=\"italics\">septies</span> entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "11": {"label": "Articolo 11", "heading": "", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora il comitato non esprima alcun parere, la Commissione non adotta il progetto di atto di esecuzione e si applica l'articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro comunica agli altri Stati membri e alla Commissione le misure adottate a norma dell'articolo 6, entro cinque giorni lavorativi dall'adozione di dette misure.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione pubblica, a titolo informativo, le comunicazioni di cui al paragrafo 1 nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "", "anchor": "art_13", "frags": [[null, "<p class=\"norm\">Il presente regolamento lascia impregiudicata la competenza degli Stati membri in materia di riconoscimento di Stati e di entità territoriali, nonché di passaporti, documenti d'identità o di viaggio rilasciati dalle autorità degli stessi.</p>"]]}, "14": {"label": "Articolo 14", "heading": "", "anchor": "art_14", "frags": [[null, "<p class=\"norm\">Il regolamento (CE) n. 539/2001 è abrogato.</p>"], [null, "<p class=\"norm\">I riferimenti al regolamento abrogato si intendono fatti al presente regolamento e si leggono secondo la tavola di concordanza riportata all'allegato IV.</p>"]]}, "15": {"label": "Articolo 15", "heading": "", "anchor": "art_15", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>.</p>"]]}}, "recitals": {}};